	public static inferFilePath(skill: Skill, title: string, description: string, evidence: string): string | null {
		const text = `${title}\n${description}\n${evidence}`;
		const candidates: string[] = [];

		for (const skillFile of skill.files) {
			candidates.push(skillFile.relativePath);
			const fileName = basename(skillFile.path);
			if (fileName !== skillFile.relativePath) {
				candidates.push(fileName);
			}
		}
		if (!candidates.includes("SKILL.md")) {
			candidates.push("SKILL.md");
		}

		candidates.sort((left, right) => right.length - left.length);
		for (const candidate of candidates) {
			if (!text.includes(candidate)) {
				continue;
			}
			for (const skillFile of skill.files) {
				if (skillFile.relativePath === candidate || basename(skillFile.path) === candidate) {
					return skillFile.relativePath;
				}
			}
			if (candidate === "SKILL.md") {
				return "SKILL.md";
			}
		}

		const lowerText = text.toLowerCase();
		if (
			lowerText.includes("skill.md") ||
			lowerText.includes("skill instructions") ||
			lowerText.includes("skill's instructions") ||
			lowerText.includes("in the skill")
		) {
			return "SKILL.md";
		}

		return null;
	}

	public isInternalFile(skill: Skill, filePath: string): boolean {
		if (filePath === "SKILL.md") {
			return true;
		}
		const normalizedPath = normalize(filePath).replaceAll("\\", "/");
		if (normalizedPath.includes("..")) {
			return false;
		}

		if (skill.files.some((file) => normalize(file.relativePath).replaceAll("\\", "/") === normalizedPath)) {
			return true;
		}

		const skillRoot = resolve(skill.directory);
		const resolvedFile = isAbsolute(filePath) ? resolve(filePath) : resolve(skillRoot, filePath);
		const withinSkill = resolvedFile === skillRoot || resolvedFile.startsWith(`${skillRoot}${sep}`);
		return withinSkill;
	}

	public setEnrichmentContext(options: SetEnrichmentContextOptions = {}): void {
		const parts: string[] = [];
		if (options.fileInventory) {
			parts.push(`File inventory: ${JSON.stringify(options.fileInventory)}`);
		}
		if (options.magicMismatches && options.magicMismatches.length > 0) {
			parts.push(`File type mismatches (extension != content): ${options.magicMismatches.join(", ")}`);
		}
		if (options.staticFindingsSummary && options.staticFindingsSummary.length > 0) {
			parts.push("Key static findings:");
			for (const finding of options.staticFindingsSummary.slice(0, 10)) {
				parts.push(`  - ${finding}`);
			}
		}
		if (typeof options.analyzabilityScore === "number") {
			parts.push(`Analyzability score: ${Math.round(options.analyzabilityScore)}%`);
		}

		this.enrichmentContext = parts.length > 0 ? parts.join("\n") : null;
	}

	private async consensusAnalyze(
		messages: Array<{ role: string; content: string }>,
		skill: Skill,
	): Promise<FindingType[]> {
		const allRunFindings: FindingType[][] = [];
		for (let runIndex = 0; runIndex < this.consensusRuns; runIndex += 1) {
			try {
				const responseContent = await this.requestHandler.makeRequest(
					messages,
					`consensus run ${runIndex + 1}/${this.consensusRuns} for ${skill.name}`,
				);
				const analysisResult = this.responseParser.parse(responseContent);
				allRunFindings.push(this.convertToFindings(analysisResult, skill));
			} catch {
				allRunFindings.push([]);
			}
		}

		const findingCounts = new Map<string, number>();
		const findingMap = new Map<string, FindingType>();
		for (const runFindings of allRunFindings) {
			const seenInRun = new Set<string>();
			for (const finding of runFindings) {
				const key = `${finding.ruleId}:${finding.category}:${finding.filePath ?? ""}`;
				if (seenInRun.has(key)) {
					continue;
				}
				findingCounts.set(key, (findingCounts.get(key) ?? 0) + 1);
				seenInRun.add(key);
				if (!findingMap.has(key)) {
					findingMap.set(key, finding);
				}
			}
		}

		const threshold = this.consensusRuns / 2;
		const consensusFindings: FindingType[] = [];
		for (const [key, count] of findingCounts.entries()) {
			if (count > threshold) {
				const finding = findingMap.get(key);
				if (finding) {
					finding.metadata.consensus_agreement = `${count}/${this.consensusRuns}`;
					consensusFindings.push(finding);
				}
			}
		}
		return consensusFindings;
	}

	private resolveDefaultModel(provider: LLMAnalyzerOptions["provider"]): string {
		const normalizedProvider = (provider ?? "anthropic").toString().toLowerCase().trim();
		const modelByProvider: Record<string, string> = {
			openai: "gpt-4o",
			anthropic: "claude-3-5-sonnet-20241022",
			"azure-openai": "azure/gpt-4o",
			"azure-ai": "azure/gpt-4",
			"aws-bedrock": "bedrock/anthropic.claude-v2",
			"gcp-vertex": "vertex_ai/gemini-1.5-pro",
			ollama: "ollama/llama2",
			openrouter: "openrouter/openai/gpt-4",
		};
		return modelByProvider[normalizedProvider] ?? "claude-3-5-sonnet-20241022";
	}
}

function isRecord(value: unknown): value is Record<string, unknown> {
	return value !== null && typeof value === "object" && !Array.isArray(value);
}

