import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";

import { generateText, jsonSchema, Output } from "ai";

import { SkillScannerConstants } from "../../../config/constants.js";
import { VALID_AITECH_CODES } from "../../../threats/taxonomy.js";
import { ProviderConfig } from "./provider-config.js";

export interface LlmMessage {
	role: "system" | "user" | "assistant" | (string & {});
	content: string;
}

export interface LlmRequestHandlerOptions {
	maxTokens?: number;
	temperature?: number;
	maxRetries?: number;
	rateLimitDelay?: number;
	timeout?: number;
}

export class LLMRequestHandler {
	public providerConfig: ProviderConfig;
	public maxTokens: number;
	public temperature: number;
	public maxRetries: number;
	public rateLimitDelay: number;
	public timeout: number;
	public responseSchema: Record<string, unknown> | null;

	constructor(providerConfig: ProviderConfig, options: LlmRequestHandlerOptions = {}) {
		this.providerConfig = providerConfig;
		this.maxTokens = options.maxTokens ?? 8_192;
		this.temperature = options.temperature ?? 0;
		this.maxRetries = options.maxRetries ?? 3;
		this.rateLimitDelay = options.rateLimitDelay ?? 2;
		this.timeout = options.timeout ?? 120;
		this.responseSchema = this.loadResponseSchema();
	}

	public loadResponseSchema(): Record<string, unknown> | null {
		try {
			const schemaPath = join(SkillScannerConstants.PROMPTS_DIR, "llm_response_schema.json");
			if (!existsSync(schemaPath)) {
				return null;
			}
			const loaded = JSON.parse(readFileSync(schemaPath, "utf-8")) as Record<string, unknown>;
			const rootProperties = asRecord(loaded.properties);
			const findings = asRecord(rootProperties.findings);
			const items = asRecord(findings.items);
			const findingProperties = asRecord(items.properties);
			const aitech = asRecord(findingProperties.aitech);
			aitech.enum = [...VALID_AITECH_CODES].sort((left, right) => left.localeCompare(right));
			findingProperties.aitech = aitech;
			items.properties = findingProperties;
			findings.items = items;
			rootProperties.findings = findings;
			loaded.properties = rootProperties;
			return loaded;
		} catch {
			return null;
		}
	}

	public sanitizeSchemaForGoogle(schema: Record<string, unknown>): Record<string, unknown> {
		const sanitized: Record<string, unknown> = {};
		for (const [key, value] of Object.entries(schema)) {
			if (key === "additionalProperties") {
				continue;
			}
			if (key === "type" && Array.isArray(value)) {
				const typeOptions = value.filter((item): item is string => typeof item === "string");
				const hasNull = typeOptions.includes("null");
				const nonNullTypes = typeOptions.filter((item) => item !== "null");
				if (nonNullTypes.length === 0) {
					throw new Error(`Google GenAI SDK does not support null-only types: ${JSON.stringify(value)}`);
				}
				if (nonNullTypes.length > 1) {
					throw new Error(`Google GenAI SDK does not support multi-type unions: ${JSON.stringify(value)}`);
				}
				sanitized.type = nonNullTypes[0]?.toUpperCase();
				if (hasNull) {
					sanitized.nullable = true;
				}
				continue;
			}
			if (key === "type" && typeof value === "string") {
				if (value === "null") {
					throw new Error("Google GenAI SDK does not support null-only types");
				}
				sanitized.type = value.toUpperCase();
				continue;
			}
			if (isRecord(value)) {
				sanitized[key] = this.sanitizeSchemaForGoogle(value);
				continue;
			}
			if (Array.isArray(value)) {
				sanitized[key] = value.map((item) => (isRecord(item) ? this.sanitizeSchemaForGoogle(item) : item));
				continue;
			}
			sanitized[key] = value;
		}
		return sanitized;
	}

	public async makeRequest(messages: LlmMessage[], context = ""): Promise<string> {
		const prompt = messages
			.map((message) => `${message.role.toUpperCase()}:\n${message.content}`)
			.join("\n\n")
			.trim();
		return this.send(prompt, { context });
	}

	public async send(prompt: string, _config?: Record<string, unknown>): Promise<string> {
		let lastError: unknown = null;
		const aiModel = ProviderConfig.getModel({
			llmModel: this.providerConfig.model,
			llmProviderApiKey: this.providerConfig.apiKey,
			llmBaseUrl: this.providerConfig.baseUrl,
			llmApiVersion: this.providerConfig.apiVersion,
		});

		for (let attempt = 0; attempt <= this.maxRetries; attempt += 1) {
			try {
				const result = this.responseSchema
					? await generateText({
							model: aiModel as never,
							prompt,
							maxOutputTokens: this.maxTokens,
							temperature: this.temperature,
							timeout: this.timeout * 1000,
							output: Output.object({
								schema: jsonSchema(this.responseSchema),
								name: "security_analysis_response",
							}),
						})
					: await generateText({
							model: aiModel as never,
							prompt,
							maxOutputTokens: this.maxTokens,
							temperature: this.temperature,
							timeout: this.timeout * 1000,
						});

				if (result.output && typeof result.output === "object") {
					return JSON.stringify(result.output);
				}
				return result.text;
			} catch (error) {
				lastError = error;
				const message = error instanceof Error ? error.message.toLowerCase() : String(error).toLowerCase();
				const retryable = ["rate limit", "quota", "too many requests", "429", "throttling"].some((token) =>
					message.includes(token),
				);

				if (retryable && attempt < this.maxRetries) {
					const delayMs = Math.trunc(1000 * this.rateLimitDelay * 2 ** attempt);
					await sleep(delayMs);
					continue;
				}
				throw error;
			}
		}

		if (lastError instanceof Error) {
			throw lastError;
		}
		throw new Error("All retries exhausted");
	}
}

function asRecord(value: unknown): Record<string, unknown> {
	if (value && typeof value === "object" && !Array.isArray(value)) {
		return value as Record<string, unknown>;
	}
	return {};
}

function isRecord(value: unknown): value is Record<string, unknown> {
	return Boolean(value) && typeof value === "object" && !Array.isArray(value);
}

function sleep(milliseconds: number): Promise<void> {
	return new Promise((resolve) => {
		setTimeout(resolve, milliseconds);
	});
