						thresholdName: "llm_analysis.max_total_prompt_chars",
					});
					lines.push(`**Referenced File: ${referencedFile}** (skipped: exceeds total budget)`);
					lines.push("");
					continue;
				}

				const extension = extname(resolvedPath).toLowerCase();
				const fileType = extension === ".md" || extension === ".markdown" ? "markdown" : "text";
				lines.push(`**Referenced File: ${referencedFile}**`);
				lines.push(`\`\`\`${fileType}`);
				lines.push(content);
