		}
	}

	private isPathWithinDirectory(path: string, directory: string): boolean {
		try {
			const resolvedPath = resolve(path);
			const resolvedDirectory = resolve(directory);
			const relative = normalize(resolvedPath).slice(normalize(resolvedDirectory).length);
			if (relative.length === 0) {
				return true;
			}
			return resolvedPath === resolvedDirectory || resolvedPath.startsWith(`${resolvedDirectory}${sep}`);
		} catch {
			return false;
		}
	}

	private findReferencedFile(skill: Skill, refFilePath: string): string | null {
		const normalizedReference = normalize(refFilePath).replaceAll("\\", "/");
		for (const skillFile of skill.files) {
			const normalizedSkillFile = normalize(skillFile.relativePath).replaceAll("\\", "/");
			if (normalizedSkillFile === normalizedReference) {
				return skillFile.path;
			}
		}

		const primaryPath = isAbsolute(refFilePath) ? refFilePath : resolve(skill.directory, refFilePath);
		if (existsSync(primaryPath)) {
			return primaryPath;
		}

		const fileName = refFilePath.split(/[\\/]/u).at(-1) ?? refFilePath;
		const alternatives = [
			resolve(skill.directory, "rules", fileName),
			resolve(skill.directory, "references", refFilePath),
			resolve(skill.directory, "assets", refFilePath),
			resolve(skill.directory, "templates", refFilePath),
		];

		for (const alternative of alternatives) {
			if (existsSync(alternative)) {
				return alternative;
			}
		}

		return null;
	}
