export type ParsedLlmResponse = Record<string, unknown>;

export class ResponseParser {
	public parse(responseContent: string): ParsedLlmResponse {
		if (!responseContent || responseContent.trim().length === 0) {
			throw new Error("Empty response from LLM");
		}

		const trimmed = responseContent.trim();
		try {
			return this.parseJsonObject(trimmed);
		} catch {
			// Fall through to extraction strategies.
		}

		let candidate = responseContent;
		if (candidate.includes("```json")) {
			const start = candidate.indexOf("```json") + 7;
			const end = candidate.indexOf("```", start);
			candidate = (end === -1 ? candidate.slice(start) : candidate.slice(start, end)).trim();
		} else if (candidate.includes("```")) {
			const start = candidate.indexOf("```") + 3;
			const end = candidate.indexOf("```", start);
			candidate = (end === -1 ? candidate.slice(start) : candidate.slice(start, end)).trim();
		}

		const startIndex = candidate.indexOf("{");
		if (startIndex !== -1) {
			let braceCount = 0;
			for (let index = startIndex; index < candidate.length; index += 1) {
				const character = candidate[index];
				if (character === "{") {
					braceCount += 1;
				} else if (character === "}") {
					braceCount -= 1;
					if (braceCount === 0) {
						const jsonCandidate = candidate.slice(startIndex, index + 1);
						return this.parseJsonObject(jsonCandidate);
					}
				}
			}
		}

		throw new Error(`Could not parse JSON from response: ${responseContent.slice(0, 200)}`);
	}

	public static parse(responseContent: string): ParsedLlmResponse {
		return new ResponseParser().parse(responseContent);
	}

	private parseJsonObject(content: string): ParsedLlmResponse {
		const parsed = JSON.parse(content);
		if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) {
			throw new Error("Parsed response is not a JSON object");
		}
		return parsed as ParsedLlmResponse;
	}
}

