	}

	public getValidatedFindings(skill: Skill): FindingType[] {
		const findings: FindingType[] = [];
		for (const findingData of this.validatedFindings) {
			try {
				const metadata = asRecord(findingData.metadata);
				if (typeof findingData.confidence === "string") {
					metadata.meta_confidence = findingData.confidence;
				}
				if (typeof findingData.confidence_reason === "string") {
					metadata.meta_confidence_reason = findingData.confidence_reason;
				}
				if (typeof findingData.exploitability === "string") {
					metadata.meta_exploitability = findingData.exploitability;
				}
				if (typeof findingData.impact === "string") {
					metadata.meta_impact = findingData.impact;
				}
				if (typeof findingData.priority_rank === "number") {
					metadata.meta_priority_rank = findingData.priority_rank;
				}
				metadata.meta_validated = true;

				findings.push(
					new Finding({
						id: typeof findingData.id === "string" ? findingData.id : `meta_${skill.name}_${String(findings.length)}`,
						ruleId: typeof findingData.rule_id === "string" ? findingData.rule_id : "META_VALIDATED",
						category: asCategory(findingData.category),
						severity: asSeverity(findingData.severity),
						title: typeof findingData.title === "string" ? findingData.title : "",
						description: typeof findingData.description === "string" ? findingData.description : "",
						filePath: typeof findingData.file_path === "string" ? findingData.file_path : null,
						lineNumber: typeof findingData.line_number === "number" ? findingData.line_number : null,
						snippet: typeof findingData.snippet === "string" ? findingData.snippet : null,
						remediation: typeof findingData.remediation === "string" ? findingData.remediation : null,
						analyzer: "meta",
						metadata,
					}),
				);
			} catch {}
		}

		return findings;
	}

	public get_validated_findings(_skill: Skill): FindingType[] {
		return this.getValidatedFindings(_skill);
	}

	public getMissedThreats(skill: Skill): FindingType[] {
		const findings: FindingType[] = [];
		for (const [index, threatData] of this.missedThreats.entries()) {
			try {
				const aitechCode = typeof threatData.aitech === "string" ? threatData.aitech : null;
				const category = asCategory(
					aitechCode !== null
						? ThreatMapping.getThreatCategoryFromAitech(aitechCode)
						: (threatData.category ?? "policy_violation"),
				);
				findings.push(
					new Finding({
						id: `meta_missed_${skill.name}_${String(index)}`,
						ruleId: "META_DETECTED",
						category,
						severity: asSeverity(threatData.severity, "HIGH"),
						title: typeof threatData.title === "string" ? threatData.title : "Threat detected by meta-analysis",
						description: typeof threatData.description === "string" ? threatData.description : "",
						filePath: typeof threatData.file_path === "string" ? threatData.file_path : null,
						lineNumber: typeof threatData.line_number === "number" ? threatData.line_number : null,
						snippet: typeof threatData.evidence === "string" ? threatData.evidence : null,
						remediation: typeof threatData.remediation === "string" ? threatData.remediation : null,
						analyzer: "meta",
						metadata: {
							meta_detected: true,
							detection_reason: typeof threatData.detection_reason === "string" ? threatData.detection_reason : "",
							meta_confidence: typeof threatData.confidence === "string" ? threatData.confidence : "MEDIUM",
							aitech: aitechCode,
						},
					}),
				);
			} catch {}
		}
		return findings;
	}

	public get_missed_threats(_skill: Skill): FindingType[] {
		return this.getMissedThreats(_skill);
	}
