export interface MetaAnalyzerOptions {
	model?: string | null;
	apiKey?: string | null;
	maxTokens?: number;
	temperature?: number;
	maxRetries?: number;
	timeout?: number;
	baseUrl?: string | null;
	apiVersion?: string | null;
	awsRegion?: string | null;
	awsProfile?: string | null;
	awsSessionToken?: string | null;
	policy?: ScanPolicy;
}

export class MetaAnalyzer extends BaseAnalyzer {
	public readonly llmPolicy: ScanPolicy["llmAnalysis"];
	public readonly model: string;
	public readonly apiKey: string | null;
	public readonly maxTokens: number;
	public readonly temperature: number;
	public readonly maxRetries: number;
	public readonly timeout: number;
	public readonly baseUrl: string | null;
	public readonly apiVersion: string | null;
	public readonly awsRegion: string | null;
	public readonly awsProfile: string | null;
	public readonly awsSessionToken: string | null;
	public systemPrompt: string;

	public constructor(options: MetaAnalyzerOptions = {}) {
		const policy = options.policy ?? ScanPolicy.default();
		super("meta_analyzer", policy);
		this.llmPolicy = policy.llmAnalysis;
		this.apiKey =
			options.apiKey ?? process.env.SKILL_SCANNER_META_LLM_API_KEY ?? process.env.SKILL_SCANNER_LLM_API_KEY ?? null;
		this.model =
			options.model ??
			process.env.SKILL_SCANNER_META_LLM_MODEL ??
			process.env.SKILL_SCANNER_LLM_MODEL ??
			"claude-3-5-sonnet-20241022";
		this.maxTokens = options.maxTokens ?? 8_192;
		this.temperature = options.temperature ?? 0.1;
		this.maxRetries = options.maxRetries ?? 3;
		this.timeout = options.timeout ?? 180;
		this.baseUrl =
			options.baseUrl ?? process.env.SKILL_SCANNER_META_LLM_BASE_URL ?? process.env.SKILL_SCANNER_LLM_BASE_URL ?? null;
		this.apiVersion =
			options.apiVersion ??
			process.env.SKILL_SCANNER_META_LLM_API_VERSION ??
			process.env.SKILL_SCANNER_LLM_API_VERSION ??
			null;
		this.awsRegion = options.awsRegion ?? null;
		this.awsProfile = options.awsProfile ?? null;
		this.awsSessionToken = options.awsSessionToken ?? null;
		this.systemPrompt = "";
		this._loadPrompts();
	}

	public analyze(_skill: Skill): FindingType[] {
		void _skill;
		return [];
	}

	public async analyzeWithFindings(
		_skill: Skill,
		_originalFindings: FindingType[],
		_analyzersUsed: string[] = [],
	): Promise<MetaAnalysisResult> {
		if (_originalFindings.length === 0) {
			return new MetaAnalysisResult({
				overallRiskAssessment: {
					risk_level: "SAFE",
					summary: "No security findings to analyze - skill appears safe.",
				},
			});
		}

		const findings = [..._originalFindings];
		const randomId = randomBytes(16).toString("hex");
		const startTag = `<!---SKILL_CONTENT_START_${randomId}--->`;
		const endTag = `<!---SKILL_CONTENT_END_${randomId}--->`;
		const [skillContext, budgetSkipped] = this._buildSkillContext(_skill);

		const llmPolicy = this.llmPolicy;
		for (const item of budgetSkipped) {
			const thresholdName = typeof item.threshold_name === "string" ? item.threshold_name : "";
			const thresholdLeaf = thresholdName.split(".").at(-1);
			const thresholdValue =
				thresholdLeaf !== undefined ? (llmPolicy as unknown as Record<string, unknown>)[thresholdLeaf] : undefined;
			const formattedThreshold =
				typeof thresholdValue === "number" ? thresholdValue.toLocaleString() : String(thresholdValue ?? "?");

			findings.push(
				new Finding({
					id: `meta_budget_${String(item.path ?? "unknown")}`,
					ruleId: "LLM_CONTEXT_BUDGET_EXCEEDED",
					category: "policy_violation",
					severity: "INFO",
					title: `'${String(item.path ?? "unknown")}' excluded from meta-analysis (${Number(item.size ?? 0).toLocaleString()} chars)`,
					description: String(item.reason ?? "Excluded from meta-analysis due to context budget policy."),
					filePath: String(item.path ?? "unknown"),
					remediation:
						thresholdLeaf === undefined
							? "Increase llm_analysis limits or llm_analysis.meta_budget_multiplier in your scan policy."
							: `Increase ${thresholdName} (currently ${formattedThreshold} x ${llmPolicy.metaBudgetMultiplier}) or llm_analysis.meta_budget_multiplier in your scan policy.`,
					analyzer: "meta_analyzer",
				}),
			);
		}

		const findingsData = this._serializeFindings(findings);
		const userPrompt = this._buildUserPrompt(_skill, skillContext, findingsData, _analyzersUsed, startTag, endTag);

		try {
			const response = await this._makeLlmRequest(this.systemPrompt, userPrompt);
			const result = this._parseResponse(response, findings);
			return await this._coverRemainingFindings(
				result,
				findings,
				_skill,
				skillContext,
				_analyzersUsed,
				startTag,
				endTag,
			);
		} catch (error) {
			const message = error instanceof Error ? error.message : String(error);
			return new MetaAnalysisResult({
				validatedFindings: findings.map((finding) => this._findingToDict(finding)),
				overallRiskAssessment: {
					risk_level: "UNKNOWN",
					summary: `Meta-analysis failed: ${message}. Original findings preserved.`,
				},
			});
		}
	}

	public async analyze_with_findings(
		_skill: Skill,
		_originalFindings: FindingType[],
		_analyzersUsed: string[] = [],
	): Promise<MetaAnalysisResult> {
