	public _buildSkillContext(_skill: Skill): [string, Array<Record<string, unknown>>] {
		const maxInstructionChars = this.policy.metaMaxInstructionBodyChars;
		const maxCodeFileChars = this.policy.metaMaxCodeFileChars;
		const maxTotalPromptChars = this.policy.metaMaxTotalPromptChars;
		const skipped: Array<Record<string, unknown>> = [];
		const lines: string[] = [];
		let totalSize = 0;

		lines.push(`## Skill: ${_skill.name}`);
		lines.push(`**Description:** ${String(_skill.description ?? "")}`);
		lines.push(`**Directory:** ${_skill.directory}`);
		lines.push("");

		lines.push("### Manifest");
		lines.push(`- License: ${_skill.manifest.license ?? "Not specified"}`);
		lines.push(`- Compatibility: ${_skill.manifest.compatibility ?? "Not specified"}`);
		const allowedTools = Array.isArray(_skill.manifest.allowedTools)
			? _skill.manifest.allowedTools
			: typeof _skill.manifest.allowedTools === "string"
				? [_skill.manifest.allowedTools]
				: [];
		lines.push(`- Allowed Tools: ${allowedTools.length > 0 ? allowedTools.join(", ") : "Not specified"}`);
		lines.push("");

		lines.push("### SKILL.md Instructions (Full)");
		const instructionSize = _skill.instructionBody.length;
		if (instructionSize > maxInstructionChars) {
			skipped.push({
				path: "SKILL.md (instruction body)",
				size: instructionSize,
				reason: `instruction body (${instructionSize.toLocaleString()} chars) exceeds meta limit (${maxInstructionChars.toLocaleString()} = ${this.llmPolicy.maxInstructionBodyChars.toLocaleString()} x ${this.llmPolicy.metaBudgetMultiplier})`,
				threshold_name: "llm_analysis.max_instruction_body_chars",
			});
			lines.push("*(instruction body excluded - exceeds budget)*");
		} else {
			lines.push(`\`\`\`markdown\n${_skill.instructionBody}\n\`\`\``);
			totalSize += instructionSize;
		}
		lines.push("");

		lines.push("### Files in Skill Package");
		for (const skillFile of _skill.files) {
			lines.push(`- ${skillFile.relativePath} (${skillFile.fileType}, ${skillFile.sizeBytes} bytes)`);
		}
		lines.push("");

		lines.push("### File Contents");
		const codeExtensions = new Set([
			".py",
			".sh",
			".bash",
			".js",
			".ts",
			".rb",
			".pl",
			".yaml",
			".yml",
			".json",
			".toml",
		]);
		for (const skillFile of _skill.files) {
			const extension = getExtension(skillFile.relativePath);
			const isCodeType = skillFile.fileType === "python" || skillFile.fileType === "bash";
			if (!codeExtensions.has(extension) && !isCodeType) {
				continue;
			}

			try {
				const content =
					typeof skillFile.content === "string"
						? skillFile.content
						: existsSync(skillFile.path)
							? readFileSync(skillFile.path, "utf-8")
							: "";
				if (content.length === 0) {
					continue;
				}

				const fileSize = content.length;
				if (fileSize > maxCodeFileChars) {
					skipped.push({
						path: skillFile.relativePath,
						size: fileSize,
						reason: `file size (${fileSize.toLocaleString()} chars) exceeds meta per-file limit (${maxCodeFileChars.toLocaleString()} = ${this.llmPolicy.maxCodeFileChars.toLocaleString()} x ${this.llmPolicy.metaBudgetMultiplier})`,
						threshold_name: "llm_analysis.max_code_file_chars",
					});
					continue;
				}

				if (totalSize + fileSize > maxTotalPromptChars) {
					skipped.push({
						path: skillFile.relativePath,
						size: fileSize,
						reason: `including this file would exceed the meta total prompt budget (${(totalSize + fileSize).toLocaleString()} > ${maxTotalPromptChars.toLocaleString()} = ${this.llmPolicy.maxTotalPromptChars.toLocaleString()} x ${this.llmPolicy.metaBudgetMultiplier})`,
						threshold_name: "llm_analysis.max_total_prompt_chars",
					});
					continue;
				}

				lines.push("");
				lines.push(`#### ${skillFile.relativePath}`);
				lines.push(`\`\`\`${extension.replace(".", "") || "text"}\n${content}\n\`\`\``);
				totalSize += fileSize;
			} catch {}
		}
		lines.push("");

		if (_skill.referencedFiles.length > 0) {
			lines.push("### Referenced Files");
			for (const referencedFile of _skill.referencedFiles) {
				lines.push(`- ${referencedFile}`);
			}
			lines.push("");
		}

		return [lines.join("\n"), skipped];
	}

	public _build_skill_context(_skill: Skill): [string, Array<Record<string, unknown>>] {
		return this._buildSkillContext(_skill);
	}

	public _serializeFindings(_findings: FindingType[]): string {
		const findingsList = _findings.map((finding, index) => ({
			_index: index,
			id: finding.id,
			rule_id: finding.ruleId,
			category: finding.category,
			severity: finding.severity,
			title: finding.title,
			description: finding.description,
			file_path: finding.filePath,
			line_number: finding.lineNumber,
			snippet: finding.snippet ? finding.snippet.slice(0, 200) : null,
			analyzer: finding.analyzer,
		}));
		return JSON.stringify(findingsList, null, 2);
	}

	public _serialize_findings(_findings: FindingType[]): string {
		return this._serializeFindings(_findings);
	}

	public _findingToDict(_finding: FindingType): Record<string, unknown> {
		return {
			id: _finding.id,
			rule_id: _finding.ruleId,
			category: _finding.category,
			severity: _finding.severity,
			title: _finding.title,
			description: _finding.description,
			file_path: _finding.filePath,
			line_number: _finding.lineNumber,
			snippet: _finding.snippet,
			remediation: _finding.remediation,
			analyzer: _finding.analyzer,
			metadata: _finding.metadata,
		};
	}

