		return this._findingToDict(_finding);
	}

	public _buildUserPrompt(
		_skill: Skill,
		_contextSummary: string,
		_serializedFindings: string,
		_analyzersUsed: string[],
		_startTag = "<!---SKILL_CONTENT_START--->",
		_endTag = "<!---SKILL_CONTENT_END--->",
	): string {
		const numFindings = _serializedFindings.match(/"_index"/gu)?.length ?? 0;
		return `## Meta-Analysis Request

You have ${String(numFindings)} findings from ${String(_analyzersUsed.length)} analyzers. Your job is to **filter the noise and prioritize what matters**.

**IMPORTANT**: You have FULL ACCESS to the skill content below - including complete SKILL.md and all code files. Use this to VERIFY findings are accurate.

### Analyzers Used
${_analyzersUsed.join(", ")}

### Skill Context (FULL CONTENT)
${_startTag}
${_contextSummary}
${_endTag}

### Findings from Analyzers (${String(numFindings)} total)
\`\`\`json
${_serializedFindings}
\`\`\`

### Your Task (IN ORDER OF IMPORTANCE)

1. **CORRELATE AND GROUP** (Most Important)
   - Group related findings into \`correlations\` (e.g., consecutive YARA hits = 1 group, pipeline + static findings about the same chain = 1 group)
   - Keep ALL grouped findings in \`validated_findings\` — correlations are for GROUPING, not removing

2. **FILTER GENUINE FALSE POSITIVES**
   - VERIFY each finding against the actual code above
   - Only mark as FP if the code is genuinely benign (keyword in comment, safe library use, internal file read)
   - Do NOT mark a finding as FP just because another analyzer already covers it

3. **PRIORITIZE BY ACTUAL RISK**
   - Put highest-priority remediation at index 0 in \`priority_order\`
   - CRITICAL: Active data exfiltration, credential theft, prompt injection
   - HIGH: Command injection, system modification
   - MEDIUM: Potential issues requiring context

4. **MAKE ACTIONABLE RECOMMENDATIONS**
   - Every recommendation needs a specific fix
   - "Don't do X" is not actionable. "Replace X with Y" is actionable.

5. **DETECT MISSED THREATS** (ONLY if obvious)
   - Leave \`missed_threats\` EMPTY unless something critical was clearly missed.

**IMPORTANT: COMPACT OUTPUT FORMAT**
- Use COMPACT format for \`validated_findings\`: only \`_index\`, \`confidence\`, \`confidence_reason\`, \`exploitability\`, \`impact\`.
- Output \`overall_risk_assessment\` and \`correlations\` FIRST in the JSON (before large arrays).
- Classify every finding (\`_index\` 0 to ${String(numFindings - 1)}) into either \`validated_findings\` or \`false_positives\`.

Respond with a JSON object containing \`validated_findings\`, \`false_positives\`, \`missed_threats\`, \`priority_order\`, \`correlations\`, \`recommendations\`, and \`overall_risk_assessment\`.`;
	}

	public _build_user_prompt(
		_skill: Skill,
		_contextSummary: string,
		_serializedFindings: string,
