	public _parseResponse(_response: string, _originalFindings: FindingType[]): MetaAnalysisResult {
		try {
			const jsonData = this._extractJsonFromResponse(_response);
			const result = new MetaAnalysisResult({
				validatedFindings: asArrayOfRecords(jsonData.validated_findings),
				falsePositives: asArrayOfRecords(jsonData.false_positives),
				missedThreats: asArrayOfRecords(jsonData.missed_threats),
				priorityOrder: asNumberArray(jsonData.priority_order),
				correlations: asArrayOfRecords(jsonData.correlations),
				recommendations: asArrayOfRecords(jsonData.recommendations),
				overallRiskAssessment: asRecord(jsonData.overall_risk_assessment),
			});
			this._enrichFindings(result, _originalFindings);
			return result;
		} catch {
			return new MetaAnalysisResult({
				validatedFindings: _originalFindings.map((finding) => this._findingToDict(finding)),
				overallRiskAssessment: {
					risk_level: "UNKNOWN",
					summary: "Failed to parse meta-analysis response",
				},
			});
		}
	}

	public _parse_response(_response: string, _originalFindings: FindingType[]): MetaAnalysisResult {
		return this._parseResponse(_response, _originalFindings);
	}

	public _extractJsonFromResponse(_response: string): Record<string, unknown> {
		const response = _response.trim();
		if (response.length === 0) {
			throw new Error("Empty response from LLM");
		}

		try {
			return asRecord(JSON.parse(response));
		} catch {
			// Continue to fallback strategies.
		}

		const markdownMatch = /```json\s*([\s\S]*?)```/iu.exec(_response);
		if (markdownMatch?.[1]) {
			try {
				return asRecord(JSON.parse(markdownMatch[1].trim()));
			} catch {
				// Continue to brace scanning.
			}
		}

		const startIndex = _response.indexOf("{");
		if (startIndex >= 0) {
			let depth = 0;
			for (let index = startIndex; index < _response.length; index += 1) {
				const char = _response[index];
				if (char === "{") {
					depth += 1;
				} else if (char === "}") {
					depth -= 1;
					if (depth === 0) {
						const candidate = _response.slice(startIndex, index + 1);
						return asRecord(JSON.parse(candidate));
					}
				}
			}
		}

		try {
			if (startIndex >= 0) {
				const jsonFragment = _response.slice(startIndex);
				const openBraces = countCharacter(jsonFragment, "{") - countCharacter(jsonFragment, "}");
				const openBrackets = countCharacter(jsonFragment, "[") - countCharacter(jsonFragment, "]");

				if (openBraces > 0 || openBrackets > 0) {
					const lastGood = Math.max(
						jsonFragment.lastIndexOf("},"),
						jsonFragment.lastIndexOf("],"),
						jsonFragment.lastIndexOf("}"),
					);
					if (lastGood > 0) {
						let repaired = jsonFragment.slice(0, lastGood + 1);
						repaired += "]}".repeat(Math.max(0, openBrackets));
						const remainingOpenBraces = countCharacter(repaired, "{") - countCharacter(repaired, "}");
						if (remainingOpenBraces > 0) {
							repaired += "}".repeat(remainingOpenBraces);
						}
						return asRecord(JSON.parse(repaired));
					}
				}
			}
		} catch {
			// Continue to final error.
		}

		throw new Error("No valid JSON found in response");
	}

	public _extract_json_from_response(_response: string): Record<string, unknown> {
		return this._extractJsonFromResponse(_response);
	}

	public _enrichFindings(_result: MetaAnalysisResult, _originalFindings: FindingType[]): void {
		const originalLookup = new Map<number, Record<string, unknown>>();
		for (const [index, finding] of _originalFindings.entries()) {
			originalLookup.set(index, this._findingToDict(finding));
		}

		for (const finding of _result.validatedFindings) {
			const index = typeof finding._index === "number" ? finding._index : null;
			if (index === null) {
				continue;
			}
			const original = originalLookup.get(index);
			if (!original) {
				continue;
			}
			for (const [key, value] of Object.entries(original)) {
				if (!(key in finding)) {
					finding[key] = value;
				}
			}
		}

		for (const finding of _result.falsePositives) {
			const index = typeof finding._index === "number" ? finding._index : null;
			if (index === null) {
				continue;
			}
			const original = originalLookup.get(index);
			if (!original) {
				continue;
			}
			for (const [key, value] of Object.entries(original)) {
				if (!(key in finding)) {
					finding[key] = value;
				}
			}
		}
	}

	public _enrich_findings(_result: MetaAnalysisResult, _originalFindings: FindingType[]): void {
		this._enrichFindings(_result, _originalFindings);
	}

	public async _coverRemainingFindings(
