export function applyMetaAnalysisToResults(
	_originalFindings: FindingType[],
	_metaResult: MetaAnalysisResult,
	_skill: Skill,
): FindingType[] {
	const falsePositiveLookup = new Map<number, { reason: string; confidence?: unknown }>();
	for (const falsePositive of _metaResult.falsePositives) {
		const index = typeof falsePositive._index === "number" ? falsePositive._index : null;
		if (index === null) {
			continue;
		}
		falsePositiveLookup.set(index, {
			reason:
				typeof falsePositive.reason === "string"
					? falsePositive.reason
					: typeof falsePositive.false_positive_reason === "string"
						? falsePositive.false_positive_reason
						: "Identified as likely false positive",
			confidence: falsePositive.confidence,
		});
	}

	const enrichmentLookup = new Map<number, Record<string, unknown>>();
	for (const validatedFinding of _metaResult.validatedFindings) {
		const index = typeof validatedFinding._index === "number" ? validatedFinding._index : null;
		if (index === null) {
			continue;
		}
		enrichmentLookup.set(index, {
			meta_validated: true,
			meta_confidence: validatedFinding.confidence,
			meta_confidence_reason: validatedFinding.confidence_reason,
			meta_exploitability: validatedFinding.exploitability,
			meta_impact: validatedFinding.impact,
		});
	}

	const priorityLookup = new Map<number, number>();
	for (const [rank, findingIndex] of _metaResult.priorityOrder.entries()) {
		priorityLookup.set(findingIndex, rank + 1);
	}

	const resultFindings: FindingType[] = [];
	for (const [index, finding] of _originalFindings.entries()) {
		if (falsePositiveLookup.has(index)) {
			const falsePositiveData = falsePositiveLookup.get(index);
			finding.metadata.meta_false_positive = true;
			finding.metadata.meta_reason = falsePositiveData?.reason;
			if (falsePositiveData?.confidence !== undefined) {
				finding.metadata.meta_confidence = falsePositiveData.confidence;
			}
		} else {
			finding.metadata.meta_false_positive = false;
			const enrichment = enrichmentLookup.get(index);
			if (enrichment) {
				for (const [key, value] of Object.entries(enrichment)) {
					if (value !== undefined) {
						finding.metadata[key] = value;
					}
				}
			} else {
				finding.metadata.meta_reviewed = true;
			}
		}

		if (priorityLookup.has(index)) {
			finding.metadata.meta_priority = priorityLookup.get(index);
		}

		resultFindings.push(finding);
	}

	for (const missedFinding of _metaResult.getMissedThreats(_skill)) {
		missedFinding.metadata.meta_false_positive = false;
		resultFindings.push(missedFinding);
	}

	return resultFindings;
}

function countCharacter(value: string, target: string): number {
	let count = 0;
	for (const character of value) {
		if (character === target) {
			count += 1;
		}
	}
	return count;
}

function sleep(milliseconds: number): Promise<void> {
	return new Promise((resolve) => {
		setTimeout(resolve, milliseconds);
	});
}

export function apply_meta_analysis_to_results(
	_originalFindings: FindingType[],
	_metaResult: MetaAnalysisResult,
	_skill: Skill,
): FindingType[] {
	return applyMetaAnalysisToResults(_originalFindings, _metaResult, _skill);
}

