import { generateText } from "ai";

import { ProviderConfig } from "../llm/provider-config.js";

export interface AlignmentLLMClientOptions {
	model?: string;
	apiKey?: string | null;
	baseUrl?: string | null;
	apiVersion?: string | null;
	temperature?: number;
	maxTokens?: number;
	timeout?: number;
}

export class AlignmentLLMClient {
	public static readonly DEFAULT_MAX_RETRIES = 3;
	public static readonly DEFAULT_RETRY_BASE_DELAY = 2;
	public static readonly PROMPT_LENGTH_THRESHOLD = 50_000;

	public readonly model: string;
	public readonly apiKey: string | null;
	public readonly baseUrl: string | null;
	public readonly apiVersion: string | null;
	public readonly temperature: number;
	public readonly maxTokens: number;
	public readonly timeout: number;

	public constructor(options: AlignmentLLMClientOptions = {}) {
		this.model = options.model ?? "gemini/gemini-2.0-flash";
		this.apiKey = options.apiKey ?? this._resolveApiKey(this.model);
		this.baseUrl = options.baseUrl ?? null;
		this.apiVersion = options.apiVersion ?? null;
		this.temperature = options.temperature ?? 0.1;
		this.maxTokens = options.maxTokens ?? 4_096;
		this.timeout = options.timeout ?? 120;

		const hasApiKey = typeof this.apiKey === "string" && this.apiKey.trim().length > 0;
		if (!hasApiKey && !this._isBedrockModel(this.model)) {
			throw new Error("LLM provider API key is required for alignment verification");
		}
	}

	public _resolveApiKey(_model: string): string | null {
		const modelLower = _model.toLowerCase();
		if (modelLower.includes("vertex")) {
			return process.env.GOOGLE_APPLICATION_CREDENTIALS ?? null;
		}
		if (modelLower.includes("ollama")) {
			return null;
		}
		return process.env.SKILL_SCANNER_LLM_API_KEY ?? null;
	}

	public _resolve_api_key(_model: string): string | null {
		return this._resolveApiKey(_model);
	}

	public _isBedrockModel(_model: string): boolean {
		return _model.toLowerCase().includes("bedrock");
	}

	public _is_bedrock_model(_model: string): boolean {
		return this._isBedrockModel(_model);
	}

	public async verifyAlignment(_prompt: string): Promise<string> {
		for (let attempt = 0; attempt < AlignmentLLMClient.DEFAULT_MAX_RETRIES; attempt += 1) {
			try {
				return await this._makeLlmRequest(_prompt);
			} catch (error) {
				if (attempt >= AlignmentLLMClient.DEFAULT_MAX_RETRIES - 1) {
					throw error;
				}
				const delayMs = AlignmentLLMClient.DEFAULT_RETRY_BASE_DELAY * 1000 * 2 ** attempt;
				await sleep(delayMs);
			}
		}
		throw new Error("All retry attempts exhausted");
	}

	public async verify_alignment(_prompt: string): Promise<string> {
		return this.verifyAlignment(_prompt);
	}

	public async _makeLlmRequest(_prompt: string): Promise<string> {
		const model = ProviderConfig.getModel({
			llmModel: this.model,
			llmProviderApiKey: this.apiKey,
			llmBaseUrl: this.baseUrl,
			llmApiVersion: this.apiVersion,
		});

		const response = await generateText({
			model: model as never,
			system:
				"You are a security expert analyzing agent skills. You receive complete dataflow analysis and code context. Analyze if the skill description accurately describes what the code actually does. Respond ONLY with valid JSON. Do not include any markdown formatting or code blocks.",
			prompt: _prompt,
			maxOutputTokens: this.maxTokens,
			temperature: this.temperature,
			timeout: this.timeout * 1000,
		});

		return response.text ?? "";
	}

	public async _make_llm_request(_prompt: string): Promise<string> {
		return this._makeLlmRequest(_prompt);
	}
}

function sleep(milliseconds: number): Promise<void> {
	return new Promise((resolve) => {
		setTimeout(resolve, milliseconds);
	});
}

