import type { SkillFunctionContext } from "../../../analysis/context-extractor.js";
import { AlignmentLLMClient } from "./alignment-llm-client.js";
import { AlignmentPromptBuilder } from "./alignment-prompt-builder.js";
import { AlignmentResponseValidator } from "./alignment-response-validator.js";
import { ThreatVulnerabilityClassifier } from "./threat-vulnerability-classifier.js";

export interface AlignmentOrchestratorOptions {
	llmModel?: string;
	llmApiKey?: string | null;
	llmBaseUrl?: string | null;
	llmTemperature?: number;
	llmMaxTokens?: number;
	llmTimeout?: number;
}

export type AlignmentCheckResult = [Record<string, unknown>, SkillFunctionContext] | null;

export class AlignmentOrchestrator {
	public readonly promptBuilder: AlignmentPromptBuilder;
	public readonly llmClient: AlignmentLLMClient;
	public readonly responseValidator: AlignmentResponseValidator;
	public readonly threatVulnClassifier: ThreatVulnerabilityClassifier;
	public readonly stats: Record<string, number>;

	public constructor(options: AlignmentOrchestratorOptions = {}) {
		this.promptBuilder = new AlignmentPromptBuilder();
		this.llmClient = new AlignmentLLMClient({
			model: options.llmModel,
			apiKey: options.llmApiKey,
			baseUrl: options.llmBaseUrl,
			temperature: options.llmTemperature,
			maxTokens: options.llmMaxTokens,
			timeout: options.llmTimeout,
		});
		this.responseValidator = new AlignmentResponseValidator();
		this.threatVulnClassifier = new ThreatVulnerabilityClassifier({
			model: options.llmModel,
			apiKey: options.llmApiKey,
			baseUrl: options.llmBaseUrl,
		});
		this.stats = {
			total_analyzed: 0,
			mismatches_detected: 0,
			no_mismatch: 0,
			skipped_invalid_response: 0,
			skipped_error: 0,
		};
	}

	public async checkAlignment(
		_funcContext: SkillFunctionContext,
		_skillDescription: string | null = null,
	): Promise<AlignmentCheckResult> {
		this.stats.total_analyzed += 1;

		try {
			const prompt = this.promptBuilder.buildPrompt(_funcContext, _skillDescription);
			const response = await this.llmClient.verifyAlignment(prompt);
			const result = this.responseValidator.validate(response);
			if (result === null) {
				this.stats.skipped_invalid_response += 1;
				return null;
			}

			if (result.mismatch_detected !== true) {
				this.stats.no_mismatch += 1;
				return null;
			}

			this.stats.mismatches_detected += 1;
			const threatName = typeof result.threat_name === "string" ? result.threat_name : "";
			if (threatName !== "GENERAL DESCRIPTION-CODE MISMATCH") {
				const classification = await this.threatVulnClassifier.classifyFinding(
					typeof result.threat_name === "string" ? result.threat_name : "UNKNOWN",
					typeof result.severity === "string" ? result.severity : "UNKNOWN",
					typeof result.summary === "string" ? result.summary : "",
					typeof result.description_claims === "string" ? result.description_claims : "",
					typeof result.actual_behavior === "string" ? result.actual_behavior : "",
					typeof result.security_implications === "string" ? result.security_implications : "",
					typeof result.dataflow_evidence === "string" ? result.dataflow_evidence : "",
				);
				result.threat_vulnerability_classification =
					typeof classification?.classification === "string" ? classification.classification : "UNCLEAR";
			}

			return [result, _funcContext];
		} catch {
			this.stats.skipped_error += 1;
			return null;
		}
	}

	public async check_alignment(
		_funcContext: SkillFunctionContext,
		_skillDescription: string | null = null,
	): Promise<AlignmentCheckResult> {
		return this.checkAlignment(_funcContext, _skillDescription);
	}

	public getStatistics(): Record<string, number> {
		return { ...this.stats };
	}

	public get_statistics(): Record<string, number> {
		return this.getStatistics();
	}
}

