import { randomBytes } from "node:crypto";
import { existsSync, readFileSync } from "node:fs";
import { join } from "node:path";

import type { SkillFunctionContext } from "../../../analysis/context-extractor.js";
import { SkillScannerConstants } from "../../../config/constants.js";

export interface AlignmentPromptBuilderOptions {
	maxOperations?: number;
	maxCalls?: number;
	maxAssignments?: number;
	maxCrossFileCalls?: number;
	maxReachableFiles?: number;
	maxConstants?: number;
	maxStringLiterals?: number;
	maxReachesCalls?: number;
}

export class AlignmentPromptBuilder {
	public maxOperationsPerParam: number;
	public maxFunctionCalls: number;
	public maxAssignments: number;
	public maxCrossFileCalls: number;
	public maxReachableFiles: number;
	public maxConstants: number;
	public maxStringLiterals: number;
	public maxReachesCalls: number;
	public template: string;

	public constructor(options: AlignmentPromptBuilderOptions = {}) {
		this.maxOperationsPerParam = options.maxOperations ?? 10;
		this.maxFunctionCalls = options.maxCalls ?? 20;
		this.maxAssignments = options.maxAssignments ?? 15;
		this.maxCrossFileCalls = options.maxCrossFileCalls ?? 10;
		this.maxReachableFiles = options.maxReachableFiles ?? 5;
		this.maxConstants = options.maxConstants ?? 10;
		this.maxStringLiterals = options.maxStringLiterals ?? 15;
		this.maxReachesCalls = options.maxReachesCalls ?? 10;
		this.template = this._loadTemplate();
	}

	public buildPrompt(_funcContext: SkillFunctionContext, _skillDescription: string | null = null): string {
		const randomId = randomBytes(16).toString("hex");
		const startTag = `<!---UNTRUSTED_INPUT_START_${randomId}--->`;
		const endTag = `<!---UNTRUSTED_INPUT_END_${randomId}--->`;
		const docstring = _funcContext.docstring ?? "No docstring provided";
		const contentParts: string[] = [];

		if (_skillDescription !== null && _skillDescription.length > 0) {
			contentParts.push(`**SKILL DESCRIPTION (from SKILL.md):**\n${_skillDescription}\n\n`);
		}

		contentParts.push(
			`**FUNCTION INFORMATION:**\n- Function Name: ${_funcContext.name}\n- Line: ${String(_funcContext.lineNumber ?? 0)}\n- Docstring/Description: ${docstring}\n\n`,
		);
		contentParts.push(
			`**FUNCTION SIGNATURE:**\n- Parameters: ${JSON.stringify(_funcContext.parameters ?? [], null, 2)}\n- Return Type: ${_funcContext.returnType ?? "Not specified"}\n`,
		);

		if (_funcContext.imports.length > 0) {
			contentParts.push(`\n**IMPORTS:**\nThe following libraries and modules are imported:\n`);
			for (const importedModule of _funcContext.imports) {
				contentParts.push(`  ${importedModule}\n`);
			}
			contentParts.push("\n");
		}

		contentParts.push(
			`\n**DATAFLOW ANALYSIS:**\nAll parameters are treated as untrusted input (skill entry points receive external data).\n\nParameter Flow Tracking:\n`,
		);

		if (_funcContext.parameterFlows.length > 0) {
			contentParts.push("\n**PARAMETER FLOW TRACKING:**\n");
			for (const flow of _funcContext.parameterFlows) {
				const parameterName = asString(flow.parameter, "unknown");
				contentParts.push(`\nParameter '${parameterName}' flows through:\n`);

				const operations = asArray(flow.operations);
				if (operations.length > 0) {
					contentParts.push(`  Operations (${String(operations.length)} total):\n`);
					for (const operation of operations.slice(0, this.maxOperationsPerParam)) {
						const operationType = asString(operation.type, "unknown");
						const line = asNumber(operation.line, 0);
						if (operationType === "assignment") {
							contentParts.push(
								`    Line ${String(line)}: ${asString(operation.target, "unknown")} = ${asString(operation.value, "unknown")}\n`,
							);
						} else if (operationType === "function_call") {
							contentParts.push(
								`    Line ${String(line)}: ${asString(operation.function, "unknown")}(${asString(operation.argument, "")})\n`,
							);
						} else if (operationType === "return") {
							contentParts.push(`    Line ${String(line)}: return ${asString(operation.value, "unknown")}\n`);
						}
					}
				}

				const reachesCalls = asStringArray(flow.reaches_calls);
				if (reachesCalls.length > 0) {
					contentParts.push(`  Reaches function calls: ${reachesCalls.slice(0, this.maxReachesCalls).join(", ")}\n`);
				}
				if (Boolean(flow.reaches_external)) {
					contentParts.push("  [WARNING] REACHES EXTERNAL OPERATIONS (file/network/subprocess)\n");
				}
				if (Boolean(flow.reaches_returns)) {
					contentParts.push("  Returns to caller\n");
				}
			}
		}

		if (Object.keys(_funcContext.variableDependencies).length > 0) {
			contentParts.push("\n**VARIABLE DEPENDENCIES:**\n");
			for (const [variable, dependencies] of Object.entries(_funcContext.variableDependencies)) {
				contentParts.push(`  ${variable} depends on: ${dependencies.join(", ")}\n`);
			}
		}

		if (_funcContext.functionCalls.length > 0) {
			contentParts.push(`\n**FUNCTION CALLS (${String(_funcContext.functionCalls.length)} total):**\n`);
			for (const call of _funcContext.functionCalls.slice(0, this.maxFunctionCalls)) {
				contentParts.push(
					`  Line ${String(asNumber(call.line, 0))}: ${asString(call.name, "unknown")}(${asStringArray(call.args).join(", ")})\n`,
				);
			}
		}

		if (_funcContext.assignments.length > 0) {
			contentParts.push(`\n**ASSIGNMENTS (${String(_funcContext.assignments.length)} total):**\n`);
			for (const assignment of _funcContext.assignments.slice(0, this.maxAssignments)) {
				contentParts.push(
					`  Line ${String(asNumber(assignment.line, 0))}: ${asString(assignment.variable, "unknown")} = ${asString(assignment.value, "unknown")}\n`,
				);
			}
		}

		if (Object.keys(_funcContext.controlFlow).length > 0) {
			contentParts.push(`\n**CONTROL FLOW:**\n${JSON.stringify(_funcContext.controlFlow, null, 2)}\n`);
		}

		if ((_funcContext.crossFileCalls ?? []).length > 0) {
			const crossFileCalls = _funcContext.crossFileCalls ?? [];
			contentParts.push(`\n**CROSS-FILE CALL CHAINS (${String(crossFileCalls.length)} calls to other files):**\n`);
			contentParts.push("[WARNING] This function calls functions from other files. Full call chains shown:\n\n");
			for (const crossCall of crossFileCalls.slice(0, this.maxCrossFileCalls)) {
				if ("to_function" in crossCall) {
					contentParts.push(
						`  ${asString(crossCall.from_function, "unknown")} -> ${asString(crossCall.to_function, "unknown")}\n`,
					);
					contentParts.push(`    From: ${asString(crossCall.from_file, "unknown")}\n`);
					contentParts.push(`    To: ${asString(crossCall.to_file, "unknown")}\n\n`);
				} else {
					contentParts.push(
						`  ${asString(crossCall.function, "unknown")}() in ${asString(crossCall.file, "unknown")}\n\n`,
					);
				}
			}
			contentParts.push("Note: Analyze the entire call chain to understand what operations are performed.\n");
		}

		if ((_funcContext.reachableFunctions ?? []).length > 0) {
			const byFile: Record<string, string[]> = {};
			for (const qualifiedFunction of _funcContext.reachableFunctions ?? []) {
				if (!qualifiedFunction.includes("::")) {
					continue;
				}
				const splitIndex = qualifiedFunction.lastIndexOf("::");
				const filePath = qualifiedFunction.slice(0, splitIndex);
				const functionName = qualifiedFunction.slice(splitIndex + 2);
				byFile[filePath] ??= [];
				byFile[filePath].push(functionName);
			}

			if (Object.keys(byFile).length > 1) {
				contentParts.push("\n**REACHABILITY ANALYSIS:**\n");
				contentParts.push(
					`Total reachable functions: ${String(_funcContext.reachableFunctions?.length ?? 0)} across ${String(Object.keys(byFile).length)} file(s)\n\n`,
				);
				for (const [index, [filePath, functions]] of Object.entries(byFile).entries()) {
					if (index >= this.maxReachableFiles) {
						break;
					}
					const fileName = filePath.split("/").at(-1) ?? filePath;
					contentParts.push(`  ${fileName}: ${functions.slice(0, 10).join(", ")}\n`);
					if (functions.length > 10) {
						contentParts.push(`    ... and ${String(functions.length - 10)} more\n`);
					}
				}
			}
		}

		if (Object.keys(_funcContext.constants).length > 0) {
			contentParts.push("\n**CONSTANTS:**\n");
			for (const [index, [key, value]] of Object.entries(_funcContext.constants).entries()) {
				if (index >= this.maxConstants) {
					break;
				}
				contentParts.push(`  ${key} = ${String(value)}\n`);
			}
		}

		if ((_funcContext.stringLiterals ?? []).length > 0) {
			contentParts.push(`\n**STRING LITERALS (${String(_funcContext.stringLiterals?.length ?? 0)} total):**\n`);
			for (const literal of (_funcContext.stringLiterals ?? []).slice(0, this.maxStringLiterals)) {
				const safeLiteral = literal.replace(/\n/gu, "\\n").replace(/\r/gu, "\\r").slice(0, 150);
				contentParts.push(`  "${safeLiteral}"\n`);
			}
		}

		if ((_funcContext.returnExpressions ?? []).length > 0) {
			contentParts.push("\n**RETURN EXPRESSIONS:**\n");
			if (_funcContext.returnType) {
				contentParts.push(`Declared return type: ${_funcContext.returnType}\n`);
			}
			for (const returnExpression of _funcContext.returnExpressions ?? []) {
				contentParts.push(`  return ${returnExpression}\n`);
			}
		}

		if ((_funcContext.exceptionHandlers ?? []).length > 0) {
			contentParts.push("\n**EXCEPTION HANDLING:**\n");
			for (const handler of _funcContext.exceptionHandlers ?? []) {
				contentParts.push(
					`  Line ${String(asNumber(handler.line, 0))}: except ${asString(handler.exception_type, "Exception")}`,
				);
				if (Boolean(handler.is_silent)) {
					contentParts.push(" ([WARNING] SILENT - just 'pass')\n");
				} else {
					contentParts.push("\n");
				}
			}
		}

		if ((_funcContext.envVarAccess ?? []).length > 0) {
			contentParts.push("\n**ENVIRONMENT VARIABLE ACCESS:**\n");
			contentParts.push("[WARNING] This function accesses environment variables:\n");
			for (const envVar of _funcContext.envVarAccess ?? []) {
				contentParts.push(`  ${envVar}\n`);
			}
		}

		if ((_funcContext.globalWrites ?? []).length > 0) {
			contentParts.push("\n**GLOBAL VARIABLE WRITES:**\n");
			contentParts.push("[WARNING] This function modifies global state:\n");
			for (const globalWrite of _funcContext.globalWrites ?? []) {
				contentParts.push(
					`  Line ${String(asNumber(globalWrite.line, 0))}: global ${asString(globalWrite.variable, "unknown")} = ${asString(globalWrite.value, "unknown")}\n`,
				);
			}
		}

		const attributeWrites = (_funcContext.attributeAccess ?? []).filter((entry) => entry.type === "write");
		if (attributeWrites.length > 0) {
			contentParts.push("\n**ATTRIBUTE WRITES:**\n");
			for (const writeOp of attributeWrites.slice(0, 10)) {
				contentParts.push(
					`  Line ${String(asNumber(writeOp.line, 0))}: ${asString(writeOp.object, "obj")}.${asString(writeOp.attribute, "field")} = ${asString(writeOp.value, "unknown")}\n`,
				);
			}
		}

		const analysisContent = contentParts.join("");
		return `${this.template}\n\n${startTag}\n${analysisContent}\n${endTag}`.trim();
	}

	public build_prompt(_funcContext: SkillFunctionContext, _skillDescription: string | null = null): string {
		return this.buildPrompt(_funcContext, _skillDescription);
	}

	public _loadTemplate(): string {
		try {
			const promptPath = join(SkillScannerConstants.PROMPTS_DIR, "skill_alignment_analysis_prompt.md");
			if (!existsSync(promptPath)) {
				return this._getEmbeddedPrompt();
			}
			const prompt = readFileSync(promptPath, "utf-8");
			return prompt.trim().length > 0 ? prompt : this._getEmbeddedPrompt();
		} catch {
			return this._getEmbeddedPrompt();
		}
	}

	public _load_template(): string {
		return this._loadTemplate();
	}

	public _getEmbeddedPrompt(): string {
		return `# Agent Skill Alignment Analysis

You are a security expert analyzing agent skills for alignment mismatches between their
described behavior and actual implementation.

## Your Task

Analyze the provided code evidence and determine if there are any mismatches between:
