	protected _jaccardSimilarity(textA: string, textB: string): number {
		const tokensA = new Set(
			(textA.toLowerCase().match(/\b[a-zA-Z]+\b/gu) ?? []).filter((token) => !STOP_WORDS.has(token)),
		);
		const tokensB = new Set(
			(textB.toLowerCase().match(/\b[a-zA-Z]+\b/gu) ?? []).filter((token) => !STOP_WORDS.has(token)),
		);
		if (tokensA.size === 0 || tokensB.size === 0) {
			return 0;
		}

		const intersectionCount = [...tokensA].filter((token) => tokensB.has(token)).length;
		const unionCount = new Set([...tokensA, ...tokensB]).size;
		return unionCount > 0 ? intersectionCount / unionCount : 0;
	}

