export class BehavioralAnalyzer extends BaseAnalyzer {
	public readonly useAlignmentVerification: boolean;
	public readonly contextExtractor: ContextExtractor;
	public readonly alignmentOrchestrator: unknown | null;

	public constructor(options: BehavioralAnalyzerOptions = {}) {
		super("behavioral_analyzer", options.policy ?? ScanPolicy.default());
		this.useAlignmentVerification = options.useAlignmentVerification ?? false;
		this.contextExtractor = new ContextExtractor();
		this.alignmentOrchestrator = null;
	}

	public async analyze(skill: Skill): Promise<Finding[]> {
		return this._analyzeStatic(skill);
	}

	protected async _analyzeStatic(skill: Skill): Promise<Finding[]> {
		const findings: Finding[] = [];
		const crossFileAnalyzer = new CrossFileAnalyzer();
		const callGraphAnalyzer = new CallGraphAnalyzer();
		const skillDescription = skill.manifest?.description ?? null;

		for (const scriptFile of skill.getScripts()) {
			if (scriptFile.fileType !== "python") {
				continue;
			}

			const content = scriptFile.readContent();
			if (content.length === 0) {
				continue;
			}

			try {
				await callGraphAnalyzer.addFile(scriptFile.path, content);
				const context = await this.contextExtractor.extractContext(scriptFile.relativePath, content);
				crossFileAnalyzer.addFileContext(scriptFile.relativePath, context);
				findings.push(...this._generateFindingsFromContext(context, skill));

				if (this.alignmentOrchestrator !== null) {
					findings.push(...(await this._runAlignmentVerification(scriptFile.path, content, skillDescription)));
				}
			} catch {}
		}

		for (const scriptFile of skill.getScripts()) {
			if (scriptFile.fileType !== "bash") {
				continue;
			}

			const content = scriptFile.readContent();
			if (content.length === 0) {
				continue;
			}

			try {
				const flows = analyzeBashScript(content, scriptFile.relativePath);
				findings.push(...this._generateFindingsFromBashFlows(flows, scriptFile.relativePath));
			} catch {}
		}

		findings.push(...this._analyzeMarkdownCodeBlocks(skill));
		callGraphAnalyzer.buildCallGraph();
		findings.push(...this._generateFindingsFromCorrelations(crossFileAnalyzer.analyzeCorrelations(), skill));
		return findings;
	}

	protected async _runAlignmentVerification(
		filePath: string,
		sourceCode: string,
		skillDescription: string | null,
	): Promise<Finding[]> {
		void filePath;
		void sourceCode;
		void skillDescription;
		return [];
	}

	protected _createAlignmentFinding(
		analysis: Record<string, unknown>,
		funcContext: SkillFunctionContext,
		filePath: string,
	): Finding | null {
		const threatNameValue = analysis.threat_name;
		const severityValue = analysis.severity;
		const threatName = typeof threatNameValue === "string" ? threatNameValue.toUpperCase() : "ALIGNMENT_MISMATCH";
		const severityString = typeof severityValue === "string" ? severityValue.toUpperCase() : "MEDIUM";
		const severityMap: Record<string, Severity> = {
			CRITICAL: "CRITICAL",
			HIGH: "HIGH",
			MEDIUM: "MEDIUM",
			LOW: "LOW",
			INFO: "LOW",
		};
		const severity = severityMap[severityString] ?? "MEDIUM";

		const categoryMap: Record<string, ThreatCategory> = {
			"DATA EXFILTRATION": "data_exfiltration",
			"CREDENTIAL THEFT": "data_exfiltration",
			"COMMAND INJECTION": "command_injection",
			"HIDDEN FUNCTIONALITY": "policy_violation",
			ALIGNMENT_MISMATCH: "policy_violation",
		};
		const category = categoryMap[threatName] ?? "policy_violation";

		const descriptionClaims = typeof analysis.description_claims === "string" ? analysis.description_claims : "";
		const actualBehavior = typeof analysis.actual_behavior === "string" ? analysis.actual_behavior : "";
		const summary =
			typeof analysis.summary === "string" ? analysis.summary : `Alignment mismatch in ${funcContext.name}`;

		const description =
			descriptionClaims.length > 0 && actualBehavior.length > 0
				? `${summary}. Description claims: '${descriptionClaims}'. Actual behavior: ${actualBehavior}`
				: summary;

		return new Finding({
			id: this._generateId(`ALIGNMENT_${threatName}`, `${filePath}:${funcContext.name}`),
			ruleId: `BEHAVIOR_ALIGNMENT_${threatName.replaceAll(" ", "_")}`,
			category,
			severity,
			title: `Alignment mismatch: ${threatName} in ${funcContext.name}`,
			description,
			filePath,
			lineNumber: funcContext.lineNumber ?? null,
			remediation: `Review function ${funcContext.name} and ensure documentation matches implementation`,
			analyzer: "behavioral",
			metadata: {
				function_name: funcContext.name,
				threat_name: threatName,
				confidence: analysis.confidence,
				security_implications: analysis.security_implications,
				dataflow_evidence: analysis.dataflow_evidence,
				classification: analysis.threat_vulnerability_classification,
			},
		});
	}

	protected _generateFindingsFromContext(context: SkillScriptContext, skill: Skill): Finding[] {
		void skill;
		const findings: Finding[] = [];

		if (context.hasNetwork && context.hasEnvVarAccess) {
			findings.push(
				new Finding({
					id: this._generateId("ENV_VAR_EXFILTRATION", context.filePath),
					ruleId: "BEHAVIOR_ENV_VAR_EXFILTRATION",
					category: "data_exfiltration",
					severity: "CRITICAL",
					title: "Environment variable access with network calls detected",
					description: `Script accesses environment variables and makes network calls in ${context.filePath}`,
					filePath: context.filePath,
					remediation: "Remove environment variable harvesting or network transmission",
					analyzer: "behavioral",
					metadata: {
						has_network: context.hasNetwork,
						has_env_access: context.hasEnvVarAccess,
						suspicious_urls: context.suspiciousUrls,
					},
				}),
			);
		}

		if (context.hasCredentialAccess) {
			findings.push(
				new Finding({
					id: this._generateId("CREDENTIAL_FILE_ACCESS", context.filePath),
					ruleId: "BEHAVIOR_CREDENTIAL_FILE_ACCESS",
					category: "data_exfiltration",
					severity: "HIGH",
					title: "Credential file access detected",
					description: `Script accesses credential files in ${context.filePath}`,
					filePath: context.filePath,
					remediation: "Remove access to ~/.aws, ~/.ssh, or other credential files",
					analyzer: "behavioral",
				}),
			);
		}

		if (context.hasEnvVarAccess) {
			findings.push(
				new Finding({
					id: this._generateId("ENV_VAR_HARVESTING", context.filePath),
					ruleId: "BEHAVIOR_ENV_VAR_HARVESTING",
					category: "data_exfiltration",
					severity: "MEDIUM",
					title: "Environment variable harvesting detected",
					description: `Script iterates through environment variables in ${context.filePath}`,
					filePath: context.filePath,
					remediation: "Remove environment variable collection unless explicitly required and documented",
					analyzer: "behavioral",
				}),
			);
		}

		for (const url of context.suspiciousUrls) {
			findings.push(
				new Finding({
					id: this._generateId("SUSPICIOUS_URL", url),
					ruleId: "BEHAVIOR_SUSPICIOUS_URL",
					category: "data_exfiltration",
					severity: "HIGH",
					title: `Suspicious URL detected: ${url}`,
					description: "Script contains suspicious URL that may be used for data exfiltration",
					filePath: context.filePath,
					remediation: "Review URL and ensure it's legitimate and documented",
					analyzer: "behavioral",
					metadata: { url },
				}),
			);
		}

		if (context.hasEvalExec && context.hasSubprocess) {
			findings.push(
				new Finding({
					id: this._generateId("EVAL_SUBPROCESS", context.filePath),
					ruleId: "BEHAVIOR_EVAL_SUBPROCESS",
					category: "command_injection",
