function inferFileType(relativePath: string, content: string | Buffer): SkillFileType {
	if (Buffer.isBuffer(content)) {
		return "binary";
	}

	const extension = extname(relativePath).toLowerCase();
	if (extension === ".py") {
		return "python";
	}
	if (extension === ".sh" || extension === ".bash") {
		return "bash";
	}
	if (extension === ".md") {
		return "markdown";
	}
	return "other";
}

function sha256(content: Buffer): string {
	return createHash("sha256").update(content).digest("hex");
}

function createSkill(tempRoot: string, files: Record<string, string | Buffer>): Skill {
	const skillDirectory = join(tempRoot, "vt-test-skill");
	mkdirSync(skillDirectory, { recursive: true });

	const skillMdPath = join(skillDirectory, "SKILL.md");
	writeFileSync(skillMdPath, "# VT test\n", "utf-8");

	const skillFiles = Object.entries(files).map(([relativePath, content]) => {
		const fullPath = join(skillDirectory, relativePath);
		mkdirSync(join(fullPath, ".."), { recursive: true });
		writeFileSync(fullPath, content);

		return new SkillFile({
			path: fullPath,
			relativePath,
			fileType: inferFileType(relativePath, content),
			content: typeof content === "string" ? content : null,
			sizeBytes: Buffer.byteLength(content),
		});
	});

	return new Skill({
		directory: skillDirectory,
		manifest: new SkillManifest({ name: "vt-test-skill", description: "VirusTotal analyzer test skill" }),
		skillMdPath,
		instructionBody: "# VT test",
		files: skillFiles,
		referencedFiles: [],
	});
