import { Skill, SkillFile, SkillManifest, type SkillFileType } from "../../../src/types/skill.js";

function inferFileType(relativePath: string): SkillFileType {
	const extension = extname(relativePath).toLowerCase();
	if (extension === ".py") {
		return "python";
	}
	if (extension === ".sh" || extension === ".bash") {
		return "bash";
	}
	if (extension === ".md") {
		return "markdown";
	}
	return "other";
}

function createSkill(tempRoot: string, instructionBody = "short", files: Record<string, string> = {}): Skill {
	const skillDirectory = join(tempRoot, "meta-test-skill");
	mkdirSync(skillDirectory, { recursive: true });

	const skillMdPath = join(skillDirectory, "SKILL.md");
	writeFileSync(skillMdPath, instructionBody, "utf-8");

	const skillFiles = Object.entries(files).map(([relativePath, content]) => {
		const fullPath = join(skillDirectory, relativePath);
		mkdirSync(join(fullPath, ".."), { recursive: true });
		writeFileSync(fullPath, content, "utf-8");
		return new SkillFile({
			path: fullPath,
			relativePath,
			fileType: inferFileType(relativePath),
			content,
			sizeBytes: Buffer.byteLength(content, "utf-8"),
		});
	});

	return new Skill({
		directory: skillDirectory,
		manifest: new SkillManifest({ name: "test-skill", description: "Meta analyzer test skill" }),
		skillMdPath,
		instructionBody,
		files: skillFiles,
		referencedFiles: [],
	});
}

