describe("LLMRequestHandler.sanitizeSchemaForGoogle", () => {
	test("converts nullable union type", () => {
		const handler = createHandler();
		const schema = { type: ["string", "null"], description: "optional" };

		const result = handler.sanitizeSchemaForGoogle(schema);

		expect(result).toEqual({
			type: "STRING",
			nullable: true,
			description: "optional",
		});
	});

	test("normalizes scalar type case", () => {
		const handler = createHandler();
		const schema = { type: "string", description: "required" };

		const result = handler.sanitizeSchemaForGoogle(schema);

		expect(result).toEqual({
			type: "STRING",
			description: "required",
		});
	});

	test("strips additionalProperties recursively", () => {
		const handler = createHandler();
		const schema = {
			type: "object",
			properties: {
				inner: {
					type: "object",
					additionalProperties: false,
					properties: {},
				},
			},
			additionalProperties: false,
		};

		const result = handler.sanitizeSchemaForGoogle(schema);
		const properties = asRecord(result.properties);
		const inner = asRecord(properties.inner);

		expect(result).not.toHaveProperty("additionalProperties");
		expect(inner).not.toHaveProperty("additionalProperties");
	});

	test("handles nested array item schemas", () => {
		const handler = createHandler();
		const schema = {
			type: "array",
			items: {
				type: "object",
				properties: {
					evidence: { type: ["string", "null"] },
				},
			},
		};

		const result = handler.sanitizeSchemaForGoogle(schema);
		const items = asRecord(result.items);
		const properties = asRecord(items.properties);
		const evidence = asRecord(properties.evidence);

		expect(evidence).toEqual({
			type: "STRING",
			nullable: true,
		});
	});

	test.each([
		["string", "STRING"],
		["number", "NUMBER"],
		["integer", "INTEGER"],
		["boolean", "BOOLEAN"],
		["array", "ARRAY"],
		["object", "OBJECT"],
	])("uppercases JSON schema type %s", (jsonType, expectedType) => {
		const handler = createHandler();

		const result = handler.sanitizeSchemaForGoogle({ type: jsonType });

		expect(result.type).toBe(expectedType);
	});

	test("throws for null-only unions", () => {
		const handler = createHandler();
		expect(() => handler.sanitizeSchemaForGoogle({ type: ["null"] })).toThrow(/null-only types/i);
		expect(() => handler.sanitizeSchemaForGoogle({ type: "null" })).toThrow(/null-only types/i);
	});

	test("throws for multi-type unions", () => {
		const handler = createHandler();
		expect(() => handler.sanitizeSchemaForGoogle({ type: ["string", "number"] })).toThrow(/multi-type unions/i);
		expect(() => handler.sanitizeSchemaForGoogle({ type: ["string", "number", "null"] })).toThrow(/multi-type unions/i);
	});

	test("sanitizes shipped response schema fixture", () => {
		const handler = createHandler();
		const schemaPath = resolve(process.cwd(), "src/data/prompts/llm_response_schema.json");
		const raw = readFileSync(schemaPath, "utf-8");
		const schema = JSON.parse(raw) as Record<string, unknown>;

		const result = handler.sanitizeSchemaForGoogle(schema);
		const findingProperties = (
			result.properties as Record<string, Record<string, Record<string, Record<string, unknown>>>>
		).findings.items.properties;

		for (const field of ["aisubtech", "location", "evidence", "remediation"]) {
			expect(findingProperties[field]).toMatchObject({
				type: "STRING",
				nullable: true,
			});
		}

		expect(findingProperties.severity).toMatchObject({ type: "STRING" });
		expect(findingProperties.severity).not.toHaveProperty("nullable");
		expect(result).not.toHaveProperty("additionalProperties");
		expect((result.properties as Record<string, unknown>).findings).toBeDefined();
	});
});

describe("LLMRequestHandler schema loading", () => {
	test("loads response schema from data/prompts", () => {
		const handler = createHandler();

		const schema = handler.loadResponseSchema();

		expect(schema).toBeTruthy();
		expect(schema).toHaveProperty("properties.findings");
	});
});

