describe("LLMAnalyzer path helpers", () => {
	test("inferFilePath chooses the most specific matching file path", () => {
		const skill = createSkill({
			"scripts/backdoor.py": "print('x')\n",
			"backdoor.py": "print('y')\n",
		});

		const inferred = LLMAnalyzer.inferFilePath(
			skill,
			"Backdoor discovered",
			"Found malicious execution in scripts/backdoor.py",
			"scripts/backdoor.py line 1",
		);

		expect(inferred).toBe("scripts/backdoor.py");
	});

	test("isInternalFile accepts known internal relative paths", () => {
		const analyzer = new LLMAnalyzer({ apiKey: "test-key" });
		const skill = createSkill({ "scripts/helper.py": "print('ok')\n" });

		expect(analyzer.isInternalFile(skill, "scripts/helper.py")).toBe(true);
	});
});

